using HaCreator.MapEditor;
using HaCreator.MapEditor.Instance;
using HaCreator.MapEditor.UndoRedo;
using System;
using System.Collections.Generic;
using System.Windows;
using System.Windows.Controls;
namespace HaCreator.GUI.InstanceEditor { public partial class LifeInstanceEditor : EditorBase { public LifeInstance item; public LifeInstanceEditor(LifeInstance item) { InitializeComponent(); this.item = item; Set(xInput, item.X); Set(yInput, item.Y); Set(rx0Box, item.rx0Shift); Set(rx1Box, item.rx1Shift); Set(yShiftBox, item.yShift); Load(item.Info, infoEnable, infoBox); Load(item.Team, teamEnable, teamBox); Load(item.MobTime, mobTimeEnable, mobTimeBox); limitedNameEnable.IsChecked = item.LimitedName != null; limitedNameBox.Text = item.LimitedName ?? string.Empty; hideBox.IsChecked = item.Hide; flipBox.IsChecked = item.Flip; pathLabel.Text = HaCreatorStateManager.CreateItemDescription(item); UpdateOptional(); } private static void Set(TextBox b, int v) => InstanceEditorDialogSupport.SetInt(b, v); private static void Load(int? v, CheckBox c, TextBox b) { c.IsChecked = v.HasValue; if (v.HasValue) Set(b, v.Value); } protected override void cancelButton_Click(object s, EventArgs e) => Close(); protected override void okButton_Click(object s, EventArgs e) { lock (item.Board.ParentControl) { int x = Get(xInput, item.X), y = Get(yInput, item.Y); List<UndoRedoAction> a = new(); if (x != item.X || y != item.Y) { a.Add(UndoRedoManager.ItemMoved(item, new Microsoft.Xna.Framework.Point(item.X, item.Y), new Microsoft.Xna.Framework.Point(x, y))); item.Move(x, y); } if (a.Count > 0) item.Board.UndoRedoMan.AddUndoBatch(a); item.rx0Shift = Get(rx0Box, item.rx0Shift); item.rx1Shift = Get(rx1Box, item.rx1Shift); item.yShift = Get(yShiftBox, item.yShift); item.MobTime = Opt(mobTimeEnable, mobTimeBox); item.Info = Opt(infoEnable, infoBox); item.Team = Opt(teamEnable, teamBox); item.LimitedName = limitedNameEnable.IsChecked == true ? limitedNameBox.Text : null; item.Hide = hideBox.IsChecked == true; item.Flip = flipBox.IsChecked == true; } Close(); } private static int Get(TextBox b, int f) => InstanceEditorDialogSupport.GetInt(b, f); private static int? Opt(CheckBox c, TextBox b) => c.IsChecked == true ? Get(b, 0) : null; private void Optional_Changed(object s, RoutedEventArgs e) => UpdateOptional(); private void UpdateOptional() { if (mobTimeBox == null) return; mobTimeBox.IsEnabled = mobTimeEnable.IsChecked == true; infoBox.IsEnabled = infoEnable.IsChecked == true; teamBox.IsEnabled = teamEnable.IsChecked == true; limitedNameBox.IsEnabled = limitedNameEnable.IsChecked == true; } private void Cancel_Click(object s, RoutedEventArgs e) => cancelButton_Click(s, EventArgs.Empty); private void Ok_Click(object s, RoutedEventArgs e) => okButton_Click(s, EventArgs.Empty); } }
